    public static InputStream inputStreamFrom(String s) {
        return new ByteArrayInputStream(s.getBytes(StandardCharsets.UTF_8));
    }

    public static String getFileAsString(File file) throws IOException {
        byte[] bytes;
        if (file.getName().endsWith(".gz")) {
            InputStream stream = new GZIPInputStream(new FileInputStream(file));
            ByteBuffer byteBuffer = DataUtil.readToByteBuffer(stream, 0);
            bytes = new byte[byteBuffer.limit()];
            System.arraycopy(byteBuffer.array(), 0, bytes, 0, byteBuffer.limit());
        } else {
            bytes = Files.readAllBytes(file.toPath());
        }
        return new String(bytes);
    }

}

package org.jsoup.integration;

import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Tag;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.MethodSource;

import java.io.File;
import java.io.IOException;
import java.util.stream.Stream;

import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

/**
 Long-running parser soak tests over known fuzz and regression fixtures. These repeat each fixture enough to catch
 timeout regressions when parser internals change; the long-running profile opts them in because timing varies by
 machine.
 <p>Run with {@code mvn -Plong-running -Dit.test=ParserSoakIT verify}</p>
 */
@Tag("long-running")
public class ParserSoakIT {
    static int numIters = 50;
    static int timeout = 30; // external fuzzer is set to 60 for 100 runs
    static File testDir = ParseTest.getFile("/fuzztests/");

    private static Stream<File> testFiles() {
        File[] files = testDir.listFiles();
        assertNotNull(files);
        assertTrue(files.length > 10);

        return Stream.of(files);
    }

    @ParameterizedTest
    @MethodSource("testFiles")
    void testHtmlParse(File file) throws IOException {
        long startTime = System.currentTimeMillis();
        long completeBy = startTime + timeout * 1000L;

        for (int i = 0; i < numIters; i++) {
            Document doc = Jsoup.parse(file, "UTF-8", "https://example.com/");
            assertNotNull(doc);
            if (System.currentTimeMillis() > completeBy)
                Assertions.fail(String.format("Timeout: only completed %d iters of [%s] in %d seconds", i, file.getName(), timeout));
        }
    }

    @ParameterizedTest
    @MethodSource("testFiles")
    void testXmlParse(File file) throws IOException {
        long startTime = System.currentTimeMillis();
        long completeBy = startTime + timeout * 1000L;

        for (int i = 0; i < numIters; i++) {
            Document doc = Jsoup.parse(file, "UTF-8", "https://example.com/", Parser.xmlParser());
            assertNotNull(doc);
            if (System.currentTimeMillis() > completeBy)
                Assertions.fail(String.format("Timeout: only completed %d iters of [%s] in %d seconds", i, file.getName(), timeout));
        }
    }
}

package org.jsoup.integration;

import org.jsoup.Connection;
import org.jsoup.Jsoup;
import org.jsoup.integration.routes.RedirectRoute;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.MethodSource;

import java.io.IOException;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.stream.Stream;

import static org.jsoup.helper.AuthenticationHandlerTest.MaxAttempts;
import static org.jsoup.integration.ConnectTest.ihVal;
import static org.jsoup.integration.TestServer.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 Tests Jsoup.connect proxy support
 */
public class ProxyTest {
    private static String echoUrl;
    private static ProxySettings proxy;

    @BeforeAll
    public static void setUp() {
        echoUrl = origin().echo.url();
        proxy = proxySettings();
    }

    @ParameterizedTest
    @MethodSource("helloUrls")
    void fetchViaProxy(String url) throws IOException {
        Connection con = Jsoup.connect(url)
            .proxy(proxy.hostname, proxy.port);

        Connection.Response res = con.execute();
        if (url.startsWith("http:/")) assertVia(res); // HTTPS CONNECT won't have Via

        Document doc = res.parse();
        Element p = doc.expectFirst("p");
        assertEquals("Hello, World!", p.text());
    }

    private static Stream<String> helloUrls() {
        return Stream.of(origin().hello.url(), origin().hello.tlsUrl());
    }

    private static Stream<String> echoUrls() {
        return Stream.of(origin().echo.url(), origin().echo.tlsUrl());
    }

    private static void assertVia(Connection.Response res) {
        assertEquals(res.header("Via"), ProxyVia);
    }

    @Test
    void redirectViaProxy() throws IOException {
        Connection.Response res = Jsoup
            .connect(origin().redirect.url())
            .data(RedirectRoute.LocationParam, echoUrl)
            .header("Random-Header-name", "hello")
            .proxy(proxy.hostname, proxy.port)
            .execute();

        assertVia(res);
        Document doc = res.parse();
        assertEquals(echoUrl, doc.location());
        assertEquals("hello", ihVal("Random-Header-name", doc));
        assertVia(res);
    }

    @Test
    void proxyForSession() throws IOException {
        Connection session = Jsoup.newSession().proxy(proxy.hostname, proxy.port);

        Connection.Response medRes = session.newRequest(origin().file.url("/htmltests/medium.html")).execute();
        Connection.Response largeRes = session.newRequest(origin().file.url("/htmltests/large.html")).execute();

        assertVia(medRes);
        assertVia(largeRes);
        assertEquals("Medium HTML", medRes.parse().title());
        assertEquals("Large HTML", largeRes.parse().title());

        Connection.Response smedRes = session.newRequest(origin().file.tlsUrl("/htmltests/medium.html")).execute();
        Connection.Response slargeRes = session.newRequest(origin().file.tlsUrl("/htmltests/large.html")).execute();

        assertEquals("Medium HTML", smedRes.parse().title());
        assertEquals("Large HTML", slargeRes.parse().title());
    }

    @ParameterizedTest
    @MethodSource("echoUrls")
    void canAuthenticateToProxy(String url) throws IOException {
        int closed =
            closeAuthedProxyConnections(); // reset any existing authed connections from previous tests, so we can test the auth flow

        // the proxy wants auth, but not the server. HTTP and HTTPS, so tests direct proxy and CONNECT
        Connection session = Jsoup.newSession()
            .proxy(proxy.hostname, proxy.authedPort)
            .ignoreHttpErrors(true)
            .ignoreContentType(true); // ignore content type, as error served may not have a content type
        String password = TestAuth.newProxyPassword();

        // fail first
        try {
            Connection.Response execute = session.newRequest(url)
                .execute();
            int code = execute.statusCode(); // no auth sent
            assertEquals(TestAuth.failureStatus(true), code);
        } catch (IOException e) {
            assertAuthRequiredException(e);
        }

        try {
            AtomicInteger count = new AtomicInteger(0);
            Connection.Response res = session.newRequest(url)
                .auth(ctx -> {
                    count.incrementAndGet();
                    return ctx.credentials(TestAuth.ProxyUser, password + "wrong"); // incorrect
                })
                .execute();
            assertEquals(MaxAttempts, count.get());
            assertEquals(TestAuth.failureStatus(true), res.statusCode());
        } catch (IOException e) {
            assertAuthRequiredException(e);
        }

        AtomicInteger successCount = new AtomicInteger(0);
        Connection.Response successRes = session.newRequest(url)
            .auth(ctx -> {
                successCount.incrementAndGet();
                return ctx.credentials(TestAuth.ProxyUser, password); // correct
            })
            .execute();
        assertEquals(1, successCount.get());
        assertEquals(200, successRes.statusCode());
    }

    static void assertAuthRequiredException(IOException e) {
        // in CONNECT (for the HTTPS url), URLConnection will throw the proxy connect as a Stringly typed IO exception - "Unable to tunnel through proxy. Proxy returns "HTTP/1.1 407 Proxy Authentication Required"". (Not a response code)
        // Alternatively, some platforms (?) will report: "No credentials provided"
        String err = e.getMessage();
        if (!(err.contains("407") || err.contains("No credentials provided") || err.contains("exch.exchImpl"))) {
            // https://github.com/jhy/jsoup/pull/2403 - Ubuntu Azul 25 throws `Cannot invoke "jdk.internal.net.http.ExchangeImpl.cancel(java.io.IOException)" because "exch.exchImpl" is null` here but is just from cancelling the 407 req
            System.err.println("Not a 407 exception? " + e.getClass());
            e.printStackTrace(System.err);
            fail("Expected 407 Proxy Authentication Required, got: " + err);
        }
    }

    @ParameterizedTest
    @MethodSource("echoUrls")
    void canAuthToProxyAndServer(String url) throws IOException {
        String serverPassword = TestAuth.newServerPassword();
        String proxyPassword = TestAuth.newProxyPassword();
        AtomicInteger count = new AtomicInteger(0);

        Connection session = Jsoup.newSession() // both proxy and server will want auth
            .proxy(proxy.hostname, proxy.authedPort)
            .header(TestAuth.WantsServerAuthentication, "1")
            .auth(auth -> {
                count.incrementAndGet();

                if (auth.isServer()) {
                    assertEquals(url, auth.url().toString());
                    assertEquals(TestAuth.ServerRealm, auth.realm());
                    return auth.credentials(TestAuth.ServerUser, serverPassword);
                } else {
                    assertTrue(auth.isProxy());
                    return auth.credentials(TestAuth.ProxyUser, proxyPassword);
                }
            });


        Connection.Response res = session.newRequest(url).execute();
        assertEquals(200, res.statusCode());
        assertEquals(2, count.get()); // hit server and proxy auth stages
        assertEquals("Webserver Environment Variables", res.parse().title());
    }
}

package org.jsoup.integration;

import org.jsoup.Connection;
import org.jsoup.Jsoup;
import org.jsoup.integration.routes.SlowRider;
import org.jsoup.nodes.Document;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.UncheckedIOException;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

import static org.jsoup.integration.TestServer.*;
import static org.junit.jupiter.api.Assertions.*;

/** Integration tests to test longer running Connection */
public class SessionIT {
    @BeforeAll
    public static void setUp() {
        start();
    }

    @Test
    public void multiThread() throws InterruptedException {
        int numThreads = 20;
        int numThreadLoops = 5;
        String[] urls = {
            origin().file.url("/htmltests/medium.html"),
            origin().file.url("/htmltests/upload-form.html"),
            origin().file.url("/htmltests/comments.html"),
            origin().file.url("/htmltests/large.html"),
        };
        String[] titles = {
            "Medium HTML",
            "Upload Form Test",
            "A Certain Kind of Test",
            "Large HTML"
        };
        ThreadCatcher catcher = new ThreadCatcher();

        Connection session = Jsoup.newSession();

        Thread[] threads = new Thread[numThreads];
        for (int threadNum = 0; threadNum < numThreads; threadNum++) {
            Thread thread = new Thread(() -> {
                for (int loop = 0; loop < numThreadLoops; loop++) {
                    for (int i = 0; i < urls.length; i++) {
                        try {
                            Document doc = session.newRequest().url(urls[i]).get();
                            assertEquals(titles[i], doc.title());
                        } catch (IOException e) {
                            throw new UncheckedIOException(e);
                        }
                    }
                }
            });
            thread.setName("Runner-" + threadNum);
            thread.start();
            thread.setUncaughtExceptionHandler(catcher);
            threads[threadNum] = thread;
        }

        // now join them all
        for (Thread thread : threads) {
            thread.join();
        }

        assertEquals(0, catcher.exceptionCount.get());
    }

    // test that we throw a nice clear exception if you try to multi-thread by forget .newRequest()
    @Test
    public void multiThreadWithoutNewRequestBlowsUp() throws InterruptedException {
        int numThreads = 5;
        String url =
            origin().slowRider.url() + "?" + SlowRider.MaxTimeParam + "=20000"; // this makes sure that the first req is still executing whilst the others run
        String title = "Slow Rider";

        ThreadCatcher catcher = new ThreadCatcher();
        Connection session = Jsoup.newSession();

        // run first slow request
        AtomicInteger successful = new AtomicInteger();
        Thread slow = new Thread(() -> {
            try {
                Document doc = session.url(url).get();
                assertNotNull(doc);
            } catch (IOException e) {
                if (!isInterruptedException(e))
                    throw new UncheckedIOException(e);
            }
        });
        slow.start();
        Thread.sleep(100); // yield so that thread can start before the next do

        // spawn others, should fail
        Thread[] threads = new Thread[numThreads];
        for (int threadNum = 0; threadNum < numThreads; threadNum++) {
            Thread thread = new Thread(() -> {
                try {
                    Document doc = session.url(url).get();
                    assertEquals(title, doc.title());
                    successful.getAndIncrement();
                } catch (IOException e) {
                    throw new UncheckedIOException(e);
                }
            });
            thread.setName("Runner-" + threadNum);
            thread.setUncaughtExceptionHandler(catcher);
            thread.start();
            threads[threadNum] = thread;
        }

        // now join them all
        for (Thread thread : threads) {
            thread.join();
        }
        // cancel the slow runner so we can wrap up the test quicker
        slow.interrupt();

        // only one should have passed, rest should have blown up (assuming the started whilst other was running)
        //assertEquals(numThreads - 1, catcher.multiThreadExceptions.get());
        //assertEquals(numThreads - 1, catcher.exceptionCount.get());

        /* The checks above work when all 20 threads are executed within 10 seconds. However, depending on how cloudy it
         is when the CI jobs are run, they may not all complete in time. As of writing that appears most commonly on the
         macOS runners, which appear overtaxed. That makes this test flaky. So we relax the test conditions, and make
         sure at least just one passed and one failed. That's OK in prod as well, because we are only concerned about
         concurrent execution, which the impl does detect correctly. */
        assertEquals(0, successful.get());
        assertTrue(catcher.multiThreadExceptions.get() > 0);
        assertEquals(catcher.multiThreadExceptions.get(),
            catcher.exceptionCount.get()); // all exceptions are multi-threaded
    }

    @Test
    public void multiThreadWithProgressListener() throws InterruptedException {
        // tests that we can use one progress listener for multiple URLs and threads.
        int numThreads = 10;
        String[] urls = {
            origin().file.url("/htmltests/medium.html"),
            origin().file.url("/htmltests/upload-form.html"),
            origin().file.url("/htmltests/comments.html"),
            origin().file.url("/htmltests/large.html"),
        };
        Set<String> seenUrls = ConcurrentHashMap.newKeySet();
        AtomicInteger completedCount = new AtomicInteger(0);
        ThreadCatcher catcher = new ThreadCatcher();

        Connection session = Jsoup.newSession()
            .onResponseProgress((processed, total, percent, response) -> {
                if (percent == 100.0f) {
                    //System.out.println("Completed " + Thread.currentThread().getName() + "- " + response.url());
                    seenUrls.add(response.url().toExternalForm());
                    completedCount.incrementAndGet();
                }
            });

        Thread[] threads = new Thread[numThreads];
        for (int threadNum = 0; threadNum < numThreads; threadNum++) {
            Thread thread = new Thread(() -> {
                for (String url : urls) {
                    try {
                        Connection con = session.newRequest().url(url);
                        con.get();
                    } catch (IOException e) {
                        throw new UncheckedIOException(e);
                    }
                }
            });
            thread.setName("Runner-" + threadNum);
            thread.setUncaughtExceptionHandler(catcher);
            thread.start();
            threads[threadNum] = thread;
        }

        // now join them all
        for (Thread thread : threads) {
            thread.join();
        }

        assertEquals(0, catcher.exceptionCount.get());
        assertEquals(urls.length, seenUrls.size());
        assertEquals(urls.length * numThreads, completedCount.get());
    }


    static class ThreadCatcher implements Thread.UncaughtExceptionHandler {
        AtomicInteger exceptionCount = new AtomicInteger();
        AtomicInteger multiThreadExceptions = new AtomicInteger();

        @Override
        public void uncaughtException(Thread t, Throwable e) {
            if (e.getMessage() != null && e.getMessage().contains("Multiple threads")) {
                multiThreadExceptions.incrementAndGet();
            } else if (!isInterruptedException(e)) {
                e.printStackTrace();
            }
            exceptionCount.incrementAndGet();
        }
    }

    private static boolean isInterruptedException(Throwable e) {
        Throwable cause = e;
        while (cause != null) {
            if (cause instanceof InterruptedException) return true;
            cause = cause.getCause();
        }
        return false;
    }

}

package org.jsoup.integration;

import org.jsoup.Connection;
import org.jsoup.Jsoup;
import org.jsoup.integration.routes.CookieRoute;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.jsoup.parser.Tag;
import org.jsoup.parser.TagSet;
import org.jsoup.select.Elements;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.Map;

import static org.jsoup.integration.TestServer.*;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

public class SessionTest {
    @BeforeAll
    public static void setUp() {
        start();
    }

    private static Elements keyEls(String key, Document doc) {
        return doc.select("th:contains(" + key + ") + td");
    }

    private static String keyText(String key, Document doc) {
        return doc.selectFirst("th:contains(" + key + ") + td").text();
    }

    @Test
    public void testPathScopedCookies() throws IOException {
        final Connection session = Jsoup.newSession();
        final String userAgent = "Jsoup Testalot v0.1";

        session.userAgent(userAgent);
        session.url(origin().cookie.url());

        // should have no cookies:
        Connection con1 = session.newRequest();
        Document doc1 = con1.get();
        assertEquals(0, doc1.select("table tr").size()); // none sent to servlet

        // set the cookies
        Connection con2 = session.newRequest().data(CookieRoute.SetCookiesParam, "1");
        Document doc2 = con2.get();
        assertEquals(0, doc2.select("table tr").size());  // none sent to servlet - we just got them!
        Map<String, String> cookies =
            con2.response().cookies(); // simple cookie response, all named "One", so should be last sent
        assertEquals(2, cookies.size());
        assertEquals("Echo", cookies.get("One"));

        // test that all response cookies are present, even if would not be sent for this request path (i.e. cookies() res can be set on a req, without using sessions)
        assertEquals("Override", cookies.get("Two"));

        // todo - interrogate cookie-store

        // check that they are sent and filtered to the right path
        Connection con3 = session.newRequest();
        Document doc3 = con3.get();
        assertCookieEndpoint(doc3);

        Document echo = session.newRequest().url(origin().echo.url()).get();
        assertEchoEndpoint(echo);
        assertEquals(userAgent, keyText("User-Agent", echo)); // check that customer user agent sent on session arrived

        // check that cookies aren't set out of the session
        Document doc4 = Jsoup.newSession().url(origin().cookie.url()).get();
        assertEquals(0, doc4.select("table tr").size()); // none sent to servlet

        // check can add local ones also
        Document doc5 = session.newRequest().cookie("Bar", "Qux").get();
        Elements doc5Bar = keyEls("Bar", doc5);
        assertEquals("Qux", doc5Bar.first().text());
    }

    // validate that only cookies scoped to the cookie endpoint path are sent there
    private void assertCookieEndpoint(Document doc) {
        assertEquals(2, doc.select("table tr").size());  // two of three sent to servlet (/ and /CookieServlet)
        Elements doc3Els = keyEls("One", doc);
        assertEquals(2, doc3Els.size());
        assertEquals("Cookie", doc3Els.get(0).text()); // ordered by most specific path
        assertEquals("Root", doc3Els.get(1).text()); // ordered by most specific path
    }

    // validate that only cookies scoped to the echo endpoint path are sent there
    private void assertEchoEndpoint(Document doc) {
        Elements echoEls = keyEls("Cookie: One", doc);  // two of three sent to servlet (/ and /EchoServlet)
        assertEquals(2, echoEls.size());
        assertEquals("Echo", echoEls.get(0).text()); // ordered by most specific path - /Echo
        assertEquals("Root", echoEls.get(1).text()); // ordered by most specific path - /
    }

    @Test
    public void testPathScopedCookiesOnRedirect() throws IOException {
        Connection session = Jsoup.newSession();

        Document doc1 = session.newRequest()
            .url(origin().cookie.url())
            .data(CookieRoute.LocationParam, origin().echo.url())
            .data(CookieRoute.SetCookiesParam, "1")
            .get();

        // we should be redirected to the echo servlet with cookies
        assertEquals(origin().echo.url(), doc1.location());
        assertEchoEndpoint(doc1); // checks we only have /echo cookies

        Document doc2 = session.newRequest()
            .url(origin().echo.url())
            .get();
        assertEchoEndpoint(doc2); // test retained in session

        Document doc3 = session.newRequest()
            .url(origin().cookie.url())
            .get();
        assertCookieEndpoint(doc3); // and so were the /cookie cookies
    }

    @Test
    public void testCanChangeParsers() throws IOException {
        Connection session = Jsoup.newSession().parser(Parser.xmlParser());

        String xmlUrl = origin().file.url("/htmltests/xml-test.xml");
        String xmlVal = "<doc><val>One<val>Two</val>Three</val></doc>\n";

        Document doc1 = session.newRequest().url(xmlUrl).get();
        assertEquals(xmlVal, doc1.html()); // not HTML normed, used XML parser

        Document doc2 = session.newRequest().parser(Parser.htmlParser()).url(xmlUrl).get();
        assertTrue(doc2.html().startsWith("<html>"));

        Document doc3 = session.newRequest().url(xmlUrl).get();
        assertEquals(xmlVal, doc3.html()); // did not blow away xml default
    }

    @Test
    public void sessionTagSetDoesNotMutateRoot() {
        Connection session = Jsoup.newSession();
        TagSet rootTags = session.request().parser().tagSet();

        int rootNamespacesBefore = tagSetNamespaceCount(rootTags);

        Connection request = session.newRequest();
        Parser parser = request.request().parser();
        parser.parseInput("<custom>One <b>Two</b></custom>", "http://example.com/");

        int rootNamespacesAfter = tagSetNamespaceCount(rootTags);
        assertEquals(rootNamespacesBefore, rootNamespacesAfter);
    }

    @Test
    public void sessionTagSetCustomizerDoesNotMutateRoot() {
        Connection session = Jsoup.newSession();
        TagSet rootTags = session.request().parser().tagSet();
        rootTags.onNewTag(tag -> {
            if (!tag.isKnownTag())
                tag.set(Tag.RcData);
        });

        int rootNamespacesBefore = tagSetNamespaceCount(rootTags);

        Connection request = session.newRequest();
        Parser parser = request.request().parser();
        Document doc = parser.parseInput("<custom>One <b>Two</b></custom>", "https://example.com/");
        assertEquals(0, doc.select("custom b").size());

        int rootNamespacesAfter = tagSetNamespaceCount(rootTags);
        assertEquals(rootNamespacesBefore, rootNamespacesAfter);
    }

    private static int tagSetNamespaceCount(TagSet tagSet) {
        try {
            Field tagsField = TagSet.class.getDeclaredField("tags");
            tagsField.setAccessible(true);
            Map<?, ?> tags = (Map<?, ?>) tagsField.get(tagSet);
            return tags.size();
        } catch (ReflectiveOperationException e) {
            throw new RuntimeException(e);
        }
    }
}

package org.jsoup.internal;

import org.jsoup.Jsoup;
import org.jsoup.SerializationException;
import org.jsoup.nodes.Document;
import org.junit.jupiter.api.Test;

import java.io.CharArrayWriter;
import java.io.IOException;

import static org.junit.jupiter.api.Assertions.*;

class QuietAppendableTest {
    @Test void wrap() {
        assertInstanceOf(
            QuietAppendable.StringBuilderAppendable.class,
            QuietAppendable.wrap(new StringBuilder())
        );

        assertInstanceOf(
            QuietAppendable.BaseAppendable.class,
            QuietAppendable.wrap(new CharArrayWriter())
        );
    }

    @Test void supplemental() {
        // hits append(char[] chars, int offset, int len) with len 2 for supplemental codepoint
        String expect = "😀";
        char[] chars = new char[2];
        chars[0] = expect.charAt(0);
        chars[1] = expect.charAt(1);
        assertEquals(2, expect.length());

        QuietAppendable sb = QuietAppendable.wrap(new StringBuilder());
        sb.append(chars, 0, 2);
        String s = sb.toString();
        assertEquals(expect, s);

        CharArrayWriter cw = new CharArrayWriter();
        QuietAppendable qa = QuietAppendable.wrap(cw);
        qa.append(chars, 0, 2);
        String out = cw.toString();
        assertEquals(expect, out);
    }

    private static Appendable brokenAppender() {
        // returns an Appendable that throws an IOException on any put
        return new Appendable() {
            @Override
            public Appendable append(CharSequence csq) throws IOException {
                throw new IOException("broken");
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) throws IOException {
                throw new IOException("broken");
            }

            @Override
            public Appendable append(char c) throws IOException {
                throw new IOException("broken");
            }
        };
    }

    @Test void appendThrowsSerializationException() {
        Document doc = Jsoup.parse("<div>");
        Appendable brokenWriter = brokenAppender();
        boolean threw = false;
        try {
            doc.html(brokenWriter);
        } catch (SerializationException e) {
            threw = true;
            Throwable cause = e.getCause();
            assertEquals("broken", cause.getMessage());
            assertInstanceOf(IOException.class, cause);
        }
        assertTrue(threw);
    }

}

package org.jsoup.internal;

import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.CharacterReader;
import org.jsoup.parser.Parser;
import org.junit.jupiter.api.Test;

import java.io.FileInputStream;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import static org.jsoup.integration.ParseTest.getPath;
import static org.junit.jupiter.api.Assertions.assertEquals;

public class ReaderTest {
    @Test void readerOfStringAndFile() throws IOException {
        // make sure that reading from a String and from a File produce the same bytes
        Path path = getPath("/fuzztests/garble.html");
        byte[] bytes = Files.readAllBytes(path);
        String fromBytes = new String(bytes, StandardCharsets.UTF_8);

        SimpleStreamReader streamReader = getReader(path);
        String fromStream = getString(streamReader);
        assertEquals(fromBytes, fromStream);

        SimpleStreamReader reader2 = getReader(path);
        CharacterReader cr = new CharacterReader(reader2);
        String fullRead = cr.consumeTo('X'); // does not exist in input
        assertEquals(fromBytes, fullRead);
    }

    private static String getString(SimpleStreamReader streamReader) throws IOException {
        // read streamreader to a string:
        StringBuilder builder = new StringBuilder();
        char[] cbuffer = new char[1024];
        int read;
        while ((read = streamReader.read(cbuffer)) != -1) {
            builder.append(cbuffer, 0, read);
        }
        return builder.toString();
    }

    private static SimpleStreamReader getReader(Path path) throws IOException {
        // set up a chain as in when we parse: simplebufferedinput -> controllableinputstream -> simplestreamreader -> characterreader
        SimpleBufferedInput input = new SimpleBufferedInput(Files.newInputStream(path));
        ControllableInputStream stream = ControllableInputStream.wrap(input, 0);
        return new SimpleStreamReader(stream, StandardCharsets.UTF_8);
    }
}

package org.jsoup.nodes;

import org.jsoup.Jsoup;
import org.jsoup.parser.ParseSettings;
import org.jsoup.parser.Parser;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;
import static org.junit.jupiter.api.Assertions.assertEquals;

public class AttributeTest {
    @Test
    public void html() {
        Attribute attr = new Attribute("key", "value &");
        assertEquals("key=\"value &amp;\"", attr.html());
        assertEquals(attr.html(), attr.toString());
    }

    @Test
    public void htmlWithLtAndGtInValue() {
        Attribute attr = new Attribute("key", "<value>");
        assertEquals("key=\"&lt;value&gt;\"", attr.html());
    }

    @Test public void testWithSupplementaryCharacterInAttributeKeyAndValue() {
        String s = new String(Character.toChars(135361));
        Attribute attr = new Attribute(s, "A" + s + "B");
        assertEquals(s + "=\"A" + s + "B\"", attr.html());
        assertEquals(attr.html(), attr.toString());
    }

    @Test public void validatesKeysNotEmpty() {
        assertThrows(IllegalArgumentException.class, () -> new Attribute(" ", "Check"));
    }

    @Test public void validatesKeysNotEmptyViaSet() {
        assertThrows(IllegalArgumentException.class, () -> {
            Attribute attr = new Attribute("One", "Check");
            attr.setKey(" ");
        });
    }

    @Test public void booleanAttributesAreEmptyStringValues() {
        Document doc = Jsoup.parse("<div hidden>");
        Attributes attributes = doc.body().child(0).attributes();
        assertEquals("", attributes.get("hidden"));

        Attribute first = attributes.iterator().next();
        assertEquals("hidden", first.getKey());
        assertEquals("", first.getValue());
        assertFalse(first.hasDeclaredValue());
        assertTrue(AttributeUtil.isBooleanAttribute(first.getKey()));
    }

    @Test public void settersOnOrphanAttribute() {
        Attribute attr = new Attribute("one", "two");
        attr.setKey("three");
        String oldVal = attr.setValue("four");
        assertEquals("two", oldVal);
        assertEquals("three", attr.getKey());
        assertEquals("four", attr.getValue());
        assertNull(attr.parent);
    }

    @Test void settersAfterParentRemoval() {
        // tests key and value set on a retained attribute after disconnected from parent
        Attributes attrs = new Attributes();
        attrs.put("foo", "bar");
        Attribute attr = attrs.attribute("foo");
        assertNotNull(attr);
        attrs.remove("foo");
        assertEquals("foo", attr.getKey());
        assertEquals("bar", attr.getValue());
        attr.setKey("new");
        attr.setValue("newer");
        assertEquals("new", attr.getKey());
        assertEquals("newer", attr.getValue());
    }

    @Test public void hasValue() {
        Attribute a1 = new Attribute("one", "");
        Attribute a2 = new Attribute("two", null);
        Attribute a3 = new Attribute("thr", "thr");

        assertTrue(a1.hasDeclaredValue());
        assertFalse(a2.hasDeclaredValue());
        assertTrue(a3.hasDeclaredValue());
    }

    @Test public void canSetValueToNull() {
        Attribute attr = new Attribute("one", "val");
        String oldVal = attr.setValue(null);
        assertEquals("one", attr.html());
        assertEquals("val", oldVal);

        oldVal = attr.setValue("foo");
        assertEquals("", oldVal); // string, not null
    }

    @Test void booleanAttributesAreNotCaseSensitive() {
        // https://github.com/jhy/jsoup/issues/1656
        assertTrue(AttributeUtil.isBooleanAttribute("required"));
        assertTrue(AttributeUtil.isBooleanAttribute("REQUIRED"));
        assertTrue(AttributeUtil.isBooleanAttribute("rEQUIREd"));
        assertFalse(AttributeUtil.isBooleanAttribute("random string"));

        String html = "<a href=autofocus REQUIRED>One</a>";
        Document doc = Jsoup.parse(html);
        assertEquals("<a href=\"autofocus\" required>One</a>", doc.selectFirst("a").outerHtml());

        Document doc2 = Jsoup.parse(html, Parser.htmlParser().settings(ParseSettings.preserveCase));
        assertEquals("<a href=\"autofocus\" REQUIRED>One</a>", doc2.selectFirst("a").outerHtml());
    }

    @Test void orphanNamespace() {
        Attribute attr = new Attribute("one", "two");
        assertEquals("", attr.namespace());
    }
}

package org.jsoup.nodes;

