    @Test
    void canSelectAndCompleteFragment() throws IOException {
        String html = "<tr id=1><td>One</td><tr id=2><td>Two</td></tr><tr id=3><td>Three</td></tr>";
        Element context = new Element("table");

        try (StreamParser parser = new StreamParser(Parser.htmlParser()).parseFragment(html, context, "")) {
            Element first = parser.expectNext("td");
            assertEquals("One", first.ownText());

            Element el = parser.expectNext("td");
            assertEquals("Two", el.ownText());

            el = parser.expectNext("td");
            assertEquals("Three", el.ownText());

            el = parser.selectNext("td");
            assertNull(el);

            List<Node> nodes = parser.completeFragment();
            assertEquals(1, nodes.size()); // should be the inferred tbody
            Node tbody = nodes.get(0);
            assertEquals("tbody", tbody.nodeName());
            List<Node> trs = tbody.childNodes();
            assertEquals(3, trs.size()); // should be the three TRs
            assertSame(trs.get(0).childNode(0), first); // tr -> td

            assertSame(parser.document(), first.ownerDocument()); // the shell document for this fragment
        }
    }

    @Test
    void canStreamFragmentXml() throws IOException {
        String html = "<tr id=1><td>One</td></tr><tr id=2><td>Two</td></tr><tr id=3><td>Three</td></tr>";
        Element context = new Element("Other");

        try (StreamParser parser = new StreamParser(Parser.xmlParser()).parseFragment(html, context, "")) {
            StringBuilder seen = new StringBuilder();
            parser.stream().forEachOrdered(el -> trackSeen(el, seen));
            assertEquals("td[One];tr#1+;td[Two];tr#2+;td[Three];tr#3;#root;", seen.toString());
            // checks expected order, and the + indicates that element had a next sibling at time of emission
            // note that we don't get a full doc, just the fragment

            assertTrue(isClosed(parser)); // as read to completion

            List<Node> nodes = parser.completeFragment();
            assertEquals(3, nodes.size());
            assertEquals("tr", nodes.get(0).nodeName());
        }
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "<html><body><a>Link</a></body></html>",
        "<html><body><a>Link</a>",
        "<a>Link</a></body></html>",
        "<a>Link</a>",
        "<a>Link",
        "<a>Link</body>",
    })
    void emitsOnlyOnce(String html) {
        try (StreamParser parser = new StreamParser(Parser.htmlParser()).parse(html, "")) {
            // https://github.com/jhy/jsoup/issues/2295
            // When there was a /body or /html, those were being emitted twice, due to firing a fake onNodeClosed to track their source positions
            StringBuilder seen = new StringBuilder();
            parser.stream().forEach(el -> trackSeen(el, seen));
            assertEquals("head+;a[Link];body;html;#root;", seen.toString());
        }
    }

}

package org.jsoup.parser;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.Map;
import java.util.concurrent.atomic.AtomicInteger;

import static org.jsoup.parser.Parser.NamespaceHtml;
import static org.junit.jupiter.api.Assertions.*;

public class TagSetTest {
    @Test void canRetrieveNewTagsSensitive() {
        Document doc = Jsoup.parse("<div><p>One</p></div>", "", Parser.htmlParser().settings(ParseSettings.preserveCase));
        TagSet tags = doc.parser().tagSet();
        // should be the full html set
        Tag meta = tags.get("meta", NamespaceHtml);
        assertNotNull(meta);
        assertTrue(meta.isKnownTag());

        Element p = doc.expectFirst("p");
        assertTrue(p.tag().isKnownTag());

        assertNull(tags.get("FOO", NamespaceHtml));
        p.tagName("FOO");
        Tag foo = p.tag();
        assertEquals("FOO", foo.name());
        assertEquals("foo", foo.normalName());
        assertEquals(NamespaceHtml, foo.namespace());
        assertFalse(foo.isKnownTag());

        assertSame(foo, tags.get("FOO", NamespaceHtml));
        assertSame(foo, tags.valueOf("FOO", NamespaceHtml));
        assertNull(tags.get("FOO", "SomeOtherNamespace"));
    }

    @Test void canRetrieveNewTagsInsensitive() {
        Document doc = Jsoup.parse("<div><p>One</p></div>");
        TagSet tags = doc.parser().tagSet();
        // should be the full html set
        Tag meta = tags.get("meta", NamespaceHtml);
        assertNotNull(meta);
        assertTrue(meta.isKnownTag());

        Element p = doc.expectFirst("p");
        assertTrue(p.tag().isKnownTag());

        assertNull(tags.get("FOO", NamespaceHtml));
        p.tagName("FOO");
        Tag foo = p.tag();
        assertEquals("foo", foo.name());
        assertEquals("foo", foo.normalName());
        assertEquals(NamespaceHtml, foo.namespace());
        assertFalse(foo.isKnownTag());

        assertSame(foo, tags.get("foo", NamespaceHtml));
        assertSame(foo, tags.valueOf("FOO", NamespaceHtml, doc.parser().settings()));
        assertNull(tags.get("foo", "SomeOtherNamespace"));
    }

    @Test void supplyCustomTagSet() {
        TagSet tags = TagSet.Html();
        tags.valueOf("custom", NamespaceHtml).set(Tag.PreserveWhitespace).set(Tag.Block);
        Parser parser = Parser.htmlParser().tagSet(tags);

        Document doc = Jsoup.parse("<body><custom>\n\nFoo\n Bar</custom></body>", parser);
        Element custom = doc.expectFirst("custom");
        assertTrue(custom.tag().preserveWhitespace());
        assertTrue(custom.tag().isBlock());
        assertEquals("<custom>\n" +
            "\n" +
            "Foo\n" +
            " Bar" +
            "</custom>", custom.outerHtml());
    }

    @Test void knownTags() {
        // tests that tags explicitly inserted via .add are 'known'; those that come implicitly via valueOf are not
        TagSet tags = TagSet.Html();
        Tag custom = new Tag("custom");
        assertEquals("custom", custom.name());
        assertEquals(NamespaceHtml, custom.namespace());
        assertFalse(custom.isKnownTag()); // not yet

        Tag br = tags.get("br", NamespaceHtml);
        assertNotNull(br);
        assertTrue(br.isKnownTag());
        assertSame(br, tags.valueOf("br", NamespaceHtml));

        Tag foo = tags.valueOf("foo", NamespaceHtml);
        assertFalse(foo.isKnownTag());

        tags.add(custom);
        assertTrue(custom.isKnownTag());
        assertSame(custom, tags.get("custom", NamespaceHtml));
        assertSame(custom, tags.valueOf("custom", NamespaceHtml));
        Tag capCustom = tags.valueOf("Custom", NamespaceHtml);
        assertTrue(capCustom.isKnownTag()); // cloned from a known tag, so is still known

        // known if set or clear called
        Tag c1 = new Tag("bar");
        assertFalse(c1.isKnownTag());
        c1.set(Tag.Block);
        assertTrue(c1.isKnownTag());
        c1.clear(Tag.Block);
        assertTrue(c1.isKnownTag());
        c1.clear(Tag.Known);
        assertFalse(c1.isKnownTag());
    }

    @Test void canCustomizeAll() {
        TagSet tags = TagSet.Html();
        tags.onNewTag(tag -> tag.set(Tag.SelfClose));
        assertTrue(tags.get("script", NamespaceHtml).is(Tag.SelfClose));
        assertTrue(tags.valueOf("SCRIPT", NamespaceHtml).is(Tag.SelfClose));
        assertTrue(tags.valueOf("custom", NamespaceHtml).is(Tag.SelfClose));

        Tag foo = new Tag("foo", NamespaceHtml);
        assertFalse(foo.is(Tag.SelfClose));
        tags.add(foo);
        assertTrue(foo.is(Tag.SelfClose));
    }

    @Test void canCustomizeSome() {
        TagSet tags = TagSet.Html();
        tags.onNewTag(tag -> {
            if (!tag.isKnownTag()) {
                tag.set(Tag.SelfClose);
            }
        });
        assertFalse(tags.valueOf("script", NamespaceHtml).is(Tag.SelfClose));
        assertFalse(tags.valueOf("SCRIPT", NamespaceHtml).is(Tag.SelfClose));
        assertTrue(tags.valueOf("custom-tag", NamespaceHtml).is(Tag.SelfClose));
    }

    @Test void canParseWithCustomization() {
        // really would use tag.valueOf("script"); just a test example here
        Parser parser = Parser.htmlParser();
        parser.tagSet().onNewTag(tag -> {
            if (tag.normalName().equals("script"))
                tag.set(Tag.SelfClose);
        });

        Document doc = Jsoup.parse("<script />Text", parser);
        assertEquals("<html>\n <head>\n  <script></script>\n </head>\n <body>Text</body>\n</html>", doc.html());
        // self closing bit still produces valid HTML
    }

    @Test void canParseWithGeneralCustomization() {
        Parser parser = Parser.htmlParser();
        parser.tagSet().onNewTag(tag -> {
            if (!tag.isKnownTag())
                tag.set(Tag.SelfClose);
        });

        Document doc = Jsoup.parse("<custom-data />Bar <script />Text", parser);
        assertEquals("<custom-data></custom-data>Bar\n<script>Text</script>", doc.body().html());
    }

    @Test void customTextBoundaryTagsAffectTextExtraction() {
        TagSet tags = TagSet.Html();
        tags.valueOf("custom-widget", NamespaceHtml).set(Tag.TextBoundary);
        Parser parser = Parser.htmlParser().tagSet(tags);

        Document doc = Jsoup.parse("<p>One<custom-widget>Two</custom-widget>Three</p>", parser);
        assertEquals("One Two Three", doc.text());
        assertEquals("OneTwoThree", doc.wholeText());
    }

    @Test void supportsMultipleCustomizers() {
        TagSet tags = TagSet.Html();
        tags.onNewTag(tag -> {
            if (tag.normalName().equals("script"))
                tag.set(Tag.SelfClose);
        });
        tags.onNewTag(tag -> {
            if (!tag.isKnownTag())
                tag.set(Tag.RcData);
        });

        assertTrue(tags.valueOf("script", NamespaceHtml).is(Tag.SelfClose));
        assertFalse(tags.valueOf("script", NamespaceHtml).is(Tag.RcData));
        assertTrue(tags.valueOf("custom-tag", NamespaceHtml).is(Tag.RcData));
    }

    @Test void customizersArePreservedInSource() {
        TagSet source = TagSet.Html();
        source.onNewTag(tag -> tag.set(Tag.RcData));
        TagSet copy = new TagSet(source);
        assertTrue(copy.valueOf("script", NamespaceHtml).is(Tag.RcData));
        assertTrue(source.valueOf("script", NamespaceHtml).is(Tag.RcData));

        copy.onNewTag(tag -> tag.set(Tag.Void));
        assertTrue(copy.valueOf("custom-tag", NamespaceHtml).is(Tag.Void));
        assertFalse(source.valueOf("custom-tag", NamespaceHtml).is(Tag.Void));
    }

    @Test void copyPullThroughDoesNotMutateSource() {
        TagSet source = TagSet.Html();
        TagSet copy = new TagSet(source);

        int sourceNamespacesBefore = tagSetNamespaceCount(source);
        assertNotNull(copy.get("div", NamespaceHtml));
        int sourceNamespacesAfter = tagSetNamespaceCount(source);
        assertEquals(sourceNamespacesBefore, sourceNamespacesAfter);
    }

    @Test void copyPullWithCustomizerThroughDoesNotMutateSource() {
        TagSet source = TagSet.Html();
        TagSet copy = new TagSet(source);

        AtomicInteger sourceAdds = new AtomicInteger();
        source.onNewTag(tag -> sourceAdds.incrementAndGet());

        assertNotNull(copy.get("div", NamespaceHtml));
        assertEquals(0, sourceAdds.get());
    }

    private static int tagSetNamespaceCount(TagSet tagSet) {
        try {
            Field tagsField = TagSet.class.getDeclaredField("tags");
            tagsField.setAccessible(true);
            Map<?, ?> tags = (Map<?, ?>) tagsField.get(tagSet);
            return tags.size();
        } catch (ReflectiveOperationException e) {
            throw new RuntimeException(e);
        }
    }
}

package org.jsoup.parser;

import org.jsoup.Jsoup;
import org.jsoup.MultiLocaleExtension.MultiLocaleTest;
import org.jsoup.nodes.Document;
import org.junit.jupiter.api.Test;

import java.util.HashMap;
import java.util.HashSet;
import java.util.Locale;

import static org.jsoup.parser.Parser.NamespaceHtml;
import static org.jsoup.parser.Parser.NamespaceSvg;
import static org.junit.jupiter.api.Assertions.*;

/**
 Tag tests.
 @author Jonathan Hedley, jonathan@hedley.net */
public class TagTest {
    @Test public void isCaseSensitive() {
        Tag p1 = Tag.valueOf("P");
        Tag p2 = Tag.valueOf("p");
        assertNotEquals(p1, p2);
    }

    @MultiLocaleTest
    public void canBeInsensitive(Locale locale) {
        Locale.setDefault(locale);

        Tag script1 = Tag.valueOf("script", NamespaceHtml, ParseSettings.htmlDefault);
        Tag script2 = Tag.valueOf("SCRIPT", NamespaceHtml, ParseSettings.htmlDefault);
        assertEquals(script1, script2);

        TagSet htmlTags = TagSet.Html();
        Tag script3 = htmlTags.valueOf("script", NamespaceHtml, ParseSettings.htmlDefault);
        Tag script4 = htmlTags.valueOf("SCRIPT", NamespaceHtml, ParseSettings.htmlDefault);
        assertSame(script3, script4);
    }

    @Test public void trims() {
        Tag p1 = Tag.valueOf("p");
        Tag p2 = Tag.valueOf(" p ");
        assertEquals(p1, p2);
    }

    @Test public void equality() {
        Tag p1 = Tag.valueOf("p");
        Tag p2 = Tag.valueOf("p");
        assertEquals(p1, p2);
        assertNotSame(p1, p2); // not same because Tag.valueOf creates new clone of the TagSet.Html, so changes don't clobber all

        TagSet html1 = TagSet.Html();
        TagSet html2 = TagSet.Html();
        assertEquals(html1, html2);
        assertNotSame(html1, html2);

        Tag p3 = html1.valueOf("p", NamespaceHtml);
        Tag p4 = html1.valueOf("p", NamespaceHtml);
        Tag p5 = html2.valueOf("p", NamespaceHtml);
        Tag p6 = html2.valueOf("p", NamespaceHtml);
        assertEquals(p1, p3);
        assertEquals(p3, p4);
        assertEquals(p4, p5);
        assertSame(p3, p4);
        assertSame(p5, p6);
        assertNotSame(p3, p5);
    }

    @Test public void divSemantics() {
        Tag div = Tag.valueOf("div");

        assertTrue(div.isBlock());
        assertFalse(div.isInline());
        assertTrue(div.isKnownTag());
    }

    @Test public void pSemantics() {
        Tag p = Tag.valueOf("p");
        assertTrue(p.isKnownTag());
        assertTrue(p.isBlock());
        assertFalse(p.isInline());
    }

    @Test public void brSemantics() {
        Tag br = Tag.valueOf("br");
        assertTrue(br.isInline());
        assertFalse(br.isBlock());
    }

    @Test public void imgSemantics() {
        Tag img = Tag.valueOf("img");
        assertTrue(img.isInline());
        assertTrue(img.isSelfClosing());
        assertFalse(img.isBlock());
    }

    @Test public void buttonSemantics() {
        Tag button = Tag.valueOf("button");
        assertTrue(button.isInline());
        assertFalse(button.isBlock());
        assertTrue(button.is(Tag.TextBoundary));
        assertTrue(button.isKnownTag());
    }

    @Test public void defaultSemantics() {
        Tag foo = Tag.valueOf("FOO"); // not defined
        Tag foo2 = Tag.valueOf("FOO");

        assertEquals(foo, foo2);
        assertFalse(foo.isKnownTag());
        assertTrue(foo.isInline());
        assertFalse(foo.isBlock());
        assertFalse(foo.is(Tag.InlineContainer));
        assertFalse(foo.preserveWhitespace());
    }

    @Test public void valueOfChecksNotNull() {
        assertThrows(IllegalArgumentException.class, () -> Tag.valueOf(null));
    }

    @Test public void valueOfChecksNotEmpty() {
        assertThrows(IllegalArgumentException.class, () -> Tag.valueOf(" "));
    }

    @Test public void knownTags() {
        assertTrue(Tag.isKnownTag("div"));
        assertFalse(Tag.isKnownTag("explain"));
    }

    @Test public void knownSvgNamespace() {
        Tag svgHtml = Tag.valueOf("svg"); // no namespace specified, defaults to html, so not the known tag
        Tag svg = Tag.valueOf("svg", Parser.NamespaceSvg, ParseSettings.htmlDefault);

        assertEquals(NamespaceHtml, svgHtml.namespace());
        assertEquals(Parser.NamespaceSvg, svg.namespace());

        assertFalse(svgHtml.isKnownTag()); // generated
        assertTrue(svg.isKnownTag()); // known
    }

    @Test public void unknownTagNamespace() {
        Tag fooHtml = Tag.valueOf("foo"); // no namespace specified, defaults to html
        Tag foo = Tag.valueOf("foo", Parser.NamespaceSvg, ParseSettings.htmlDefault);

        assertEquals(NamespaceHtml, fooHtml.namespace());
        assertEquals(Parser.NamespaceSvg, foo.namespace());

        assertFalse(fooHtml.isKnownTag()); // generated
        assertFalse(foo.isKnownTag()); // generated
    }

    @Test void canSetOptions() {
        Tag tag = new Tag("foo", NamespaceHtml);
        assertFalse(tag.isKnownTag());
        assertFalse(tag.isEmpty());
        tag.set(Tag.Void);
        assertTrue(tag.isEmpty());
        assertTrue(tag.isKnownTag());
    }

    @Test void textBoundaryOption() {
        Tag tag = new Tag("foo", NamespaceHtml);
        assertFalse(tag.is(Tag.TextBoundary));
        tag.set(Tag.TextBoundary);
        assertTrue(tag.is(Tag.TextBoundary));
        assertTrue(tag.isKnownTag());
    }

    @Test void updateNameAndNamespace() {
        Tag tag = new Tag("foo", NamespaceHtml);
        tag.name("bar").namespace(NamespaceSvg);
        tag.set(Tag.Block);
        assertEquals("bar", tag.name());
        assertEquals(NamespaceSvg, tag.namespace());
        assertTrue(tag.isBlock()); // properties are unchanged

        // test in a doc
        Document doc = Jsoup.parse("<foo>One</foo><foo>Two</foo>");
        Tag foo = doc.expectFirst("foo").tag();
        foo.name("BAR");
        assertEquals("<BAR>One</BAR><BAR>Two</BAR>", doc.body().html()); // is case-sensitive
    }

    @Test void formSubmittable() {
        // https://github.com/jhy/jsoup/issues/2323
        Tag img = Tag.valueOf("img");
        Tag input = Tag.valueOf("input");
        int imgOpts = img.options;
        int inputOpts = input.options;
        assertFalse(img.isFormSubmittable());
        assertTrue(input.isFormSubmittable());
        assertEquals(imgOpts, img.options);
        assertEquals(inputOpts, input.options);
    }

    @Test void stableHashcode() {
        // tests that the hashcode is stable and suitable as a key
        HashSet<Tag> tags = new HashSet<>();
        Tag img = Tag.valueOf("img");
        Tag IMG = Tag.valueOf("IMG");
        Tag imgS = Tag.valueOf("img", NamespaceSvg, ParseSettings.htmlDefault);

        assertEquals(-2074969810, img.hashCode());
        assertEquals(-2075954866, IMG.hashCode());
        assertEquals(-292873947, imgS.hashCode());

        tags.add(img);
        tags.add(IMG);
        tags.add(imgS);

        imgS.set(Tag.Block);
        assertEquals(-292873947, imgS.hashCode());

        assertTrue(tags.contains(img));
        assertTrue(tags.contains(IMG));
        assertTrue(tags.contains(imgS));
    }

    @Test void prefix() {
        Tag img = Tag.valueOf("img");
        Tag book = Tag.valueOf("bk:book");

        assertEquals("", img.prefix());
        assertEquals("bk", book.prefix());
    }

    @Test void localname() {
        Tag img = Tag.valueOf("img");
        Tag book = Tag.valueOf("bk:book");

        assertEquals("img", img.localName());
        assertEquals("book", book.localName());
    }

    @Test void valueOfWithSettings() {
        Tag img1 = Tag.valueOf("img", ParseSettings.htmlDefault);
        Tag img2 = Tag.valueOf("IMG", ParseSettings.htmlDefault);
        Tag img3 = Tag.valueOf("IMG", ParseSettings.preserveCase);

        assertNotSame(img1, img2); // because we are creating new TagSets with html()
        assertNotSame(img1, img3);
        assertEquals("IMG", img3.toString());
        assertEquals("img", img1.toString());

        TagSet tagSet = TagSet.Html();
        assertSame(
            tagSet.valueOf("img", NamespaceHtml, ParseSettings.htmlDefault),
            tagSet.valueOf("IMG", NamespaceHtml, ParseSettings.htmlDefault)
        );

        assertNotSame(
            tagSet.valueOf("img", NamespaceHtml),
            tagSet.valueOf("IMG", NamespaceHtml)
        );
    }

    @Test void equals() {
        TagSet tags = TagSet.Html();
        Tag p1 = tags.get("p", NamespaceHtml);
        Tag p2 = p1.clone();
        assertEquals(p1, p2);
        assertNotEquals(p1, tags);

        p2.namespace = "Other";
        assertNotEquals(p1, p2);
        p2.namespace = p1.namespace;

        p2.tagName = "P";
        assertNotEquals(p1, p2);
        p2.tagName = p1.tagName;

        p2.normalName = "pp";
        assertNotEquals(p1, p2);
        p2.normalName = p1.normalName;

        p2.options = 0;
        assertNotEquals(p1, p2);
        p2.options = p1.options;
    }
}

package org.jsoup.parser;

import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
