        assertEquals(2, ul.childrenSize());

        Element li1 = ul.expectFirst("> li:nth-child(1)");
        assertEquals("Foo", li1.ownText());
        assertTrue(li1.select("ul").isEmpty());

        Element li2 = ul.expectFirst("> li:nth-child(2)");
