        assertEquals("body;div;p;span;child;", headOrder.toString());
        assertEquals("child;span;p;div;body;", tailOrder.toString());
        assertEquals("<div><p><span>child</span></p></div>", TextUtil.stripNewlines(doc.body().html()));
